import{j as o,c as t,b as i,ah as a}from"./chunks/framework.Br27zpCu.js";const b=JSON.parse('{"title":"Debugging Basics","description":"","frontmatter":{},"headers":[],"relativePath":"bagisto-native/native-integration/android/build-and-run/debugging-basics.md","filePath":"bagisto-native/native-integration/android/build-and-run/debugging-basics.md","lastUpdated":1773897321000}'),n={name:"bagisto-native/native-integration/android/build-and-run/debugging-basics.md"};function r(s,e,l,d,g,c){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="debugging-basics" tabindex="-1">Debugging Basics <a class="header-anchor" href="#debugging-basics" aria-label="Permalink to &quot;Debugging Basics&quot;">​</a></h1><p>Efficiently troubleshooting your Bagisto Native Android app involves using both Android Studio and web development tools.</p><h2 id="_1-android-studio-logcat" tabindex="-1">1. Android Studio Logcat <a class="header-anchor" href="#_1-android-studio-logcat" aria-label="Permalink to &quot;1. Android Studio Logcat&quot;">​</a></h2><p>The primary source for native errors and bridge logs.</p><ul><li><strong>Initialization Logs</strong>: Check if the Navigator starts correctly.</li><li><strong>Bridge Messages</strong>: Enable debug logging to see every message sent from web to native.</li><li><strong>Kotlin Crashes</strong>: Look for stack traces if the app closes unexpectedly.</li></ul><h2 id="_2-chrome-devtools" tabindex="-1">2. Chrome DevTools <a class="header-anchor" href="#_2-chrome-devtools" aria-label="Permalink to &quot;2. Chrome DevTools&quot;">​</a></h2><p>Essential for debugging the web content inside the WebView.</p><ul><li><strong>Console</strong>: View JavaScript errors or network failures.</li><li><strong>Network Tab</strong>: See if API calls from the headless storefront are failing.</li><li><strong>Elements</strong>: Inspect the DOM to ensure bridge component tags are correctly formatted.</li></ul><p>To connect:</p><ol><li>Enable WebView debugging in your app: <code>WebView.setWebContentsDebuggingEnabled(true)</code></li><li>Open Chrome on your computer and navigate to <code>chrome://inspect</code></li><li>Click on your app&#39;s WebView</li></ol><h2 id="_3-common-troubleshooting" tabindex="-1">3. Common Troubleshooting <a class="header-anchor" href="#_3-common-troubleshooting" aria-label="Permalink to &quot;3. Common Troubleshooting&quot;">​</a></h2><p>If the build is failing or weirdly stuck:</p><ol><li><strong>Clean Project</strong>: <code>Build → Clean Project</code></li><li><strong>Rebuild Project</strong>: <code>Build → Rebuild Project</code></li><li><strong>Invalidate Caches</strong>: <code>File → Invalidate Caches → Invalidate and Restart</code></li></ol>',13)])])}const h=o(n,[["render",r]]);export{b as __pageData,h as default};
